import{_ as e,c as t,o as r,ag as n}from"./chunks/framework.DPDPlp3K.js";const p=JSON.parse('{"title":"如何区分数据结构中的线性结构与非线性结构？","description":"","frontmatter":{},"headers":[],"relativePath":"linear-vs-nonlinear-data-structure.md","filePath":"linear-vs-nonlinear-data-structure.md"}'),l={name:"linear-vs-nonlinear-data-structure.md"};function i(o,a,s,c,d,u){return r(),t("div",null,a[0]||(a[0]=[n('<h1 id="如何区分数据结构中的线性结构与非线性结构" tabindex="-1">如何区分数据结构中的线性结构与非线性结构？ <a class="header-anchor" href="#如何区分数据结构中的线性结构与非线性结构" aria-label="Permalink to &quot;如何区分数据结构中的线性结构与非线性结构？&quot;">​</a></h1><p>数据结构可以分成两种：</p><ul><li>线性结构</li><li>非线性结构</li></ul><p>下面就来简单聊聊这两种结构，至于具体的数据结构，后续的文章还会再做说明，别着急。</p><h2 id="线性结构" tabindex="-1">线性结构 <a class="header-anchor" href="#线性结构" aria-label="Permalink to &quot;线性结构&quot;">​</a></h2><p>先来说线性结构，怎么理解呢？线性结构的元素之间是一个接着一个连接，构成线性的形式。比如数组、链表、栈、队列等。</p><ul><li>对于数组，元素依次顺序存放，紧挨着，是一种<strong>顺序存储方式</strong>。</li><li>对于链表，元素之间离散存储，通过指针彼此相连，是一种<strong>链式存储方式</strong>。</li><li>对于栈跟队列，可以用上面两种结构：数组或链表来实现。</li></ul><h2 id="非线性结构" tabindex="-1">非线性结构 <a class="header-anchor" href="#非线性结构" aria-label="Permalink to &quot;非线性结构&quot;">​</a></h2><p>非线性结构，也挺好理解。非线性结构的元素可以有多个子元素与之关联。比如，树结构，一个节点可以有左右子节点；图结构，每个节点都可以与多个节点关联，从而构成复杂网络。</p>',9)]))}const h=e(l,[["render",i]]);export{p as __pageData,h as default};
